// // This comment suggests the counter decrements on each clock edge
module top_module(
    input clk,
    input reset,
    output reg [3:0] count
);always @(posedge clk or posedge reset)
    begin
        if (reset)
            count <= 4'b0000;
        else
            count <= count + 1;
    end

endmodule
